INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Multi-language support$q$, $q$Use Taiga's interface in 20 or more languages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Fully open source with a genuinely free self-hosted option$q$, 0);
