INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Affordable cloud pricing compared to many commercial project management tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Approachable interface for both developers and non-technical team members$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Active open-source community and regular updates$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Free cloud tier has very limited storage and project count$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
