INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Premium support tiers require the higher-priced cloud or private cloud plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Company size and roadmap resources are limited compared to venture-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Is Taiga free?$q$, $q$Yes, Taiga offers a free cloud tier with limited projects and storage, and the platform is fully open source under AGPL-3.0-or-later, so teams can self-host it for free.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$What methodologies does Taiga support?$q$, $q$Taiga is built specifically for agile teams and natively supports both Scrum and Kanban workflows, including backlogs, sprints, epics, and Kanban boards.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$How much does Taiga cost?$q$, $q$Taiga's cloud plans range from a free tier up to roughly 60 euros per month for the Premium tier, with Enthusiast and Basic tiers priced in between, plus custom pricing for dedicated private cloud or on-premises deployments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Who develops Taiga?$q$, $q$Taiga is developed and maintained by Kaleidos, a software studio based in Madrid, Spain, which also builds the open-source design tool Penpot.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Can Taiga be self-hosted?$q$, $q$Yes, because Taiga is fully open source under the AGPL-3.0-or-later license, organizations can self-host it on their own infrastructure at no licensing cost.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$When was Taiga founded?$q$, $q$Taiga originated from a 2013 hackathon at Kaleidos and launched publicly in 2014, co-led by Enrique Posner and Pablo Ruiz Muzquiz.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Does Taiga integrate with GitHub or GitLab?$q$, $q$Yes, Taiga supports integrations with development tools including GitHub, GitLab, and Slack.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Is Taiga a good Jira alternative?$q$, $q$Taiga is often used as an open-source, more affordable alternative to Jira, particularly by teams that want a self-hosted option or prefer a simpler agile-focused interface.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Agile software development$q$, $q$Run Scrum sprints or Kanban workflows for software teams tracking user stories and bugs.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Open-source project management$q$, $q$Coordinate contributors and issues for open-source community projects using a free, self-hostable tool.$q$, $q$Open-source project maintainers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Self-hosted internal project tracking$q$, $q$Deploy Taiga on internal infrastructure for organizations with data residency or budget constraints.$q$, $q$IT teams and small to mid-size businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Free$q$, $q$EUR 0$q$, $q$N/A$q$, NULL, $q$["1 public project, 1 private project","10MB storage","Unlimited users","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Enthusiast$q$, $q$EUR 5/month (EUR 50/year)$q$, $q$Monthly or annual$q$, NULL, $q$["5 public projects, 5 private projects","100MB storage","Unlimited users","Community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Basic$q$, $q$EUR 20/month (EUR 200/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited projects","500MB storage","Unlimited users","Basic support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Premium$q$, $q$EUR 60/month (EUR 600/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited projects","3GB storage","Unlimited users","Premium support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$Taiga Private Cloud$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Dedicated instance hosted by Taiga Cloud Services","8GB RAM, 2 vCPU, 100GB SSD","Unlimited projects and users","Managed updates and instance dashboard"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$On Premise$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Priority support with SLA","Firewall or VPN deployment","Unlimited projects and users","Installation support and managed updates"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$overview$q$, $q$What Is Taiga$q$, 2, ARRAY[$q$Taiga is an open-source project management tool built specifically for agile teams using Scrum or Kanban methodologies. It provides backlog management, sprint planning, Kanban boards, and issue tracking in an interface designed to be approachable for both developers and non-technical team members like designers.$q$, $q$Taiga originated from a 2013 hackathon at Kaleidos, a software studio based in Madrid, Spain, and launched publicly in 2014. It is released under the AGPL-3.0-or-later open-source license, meaning teams can self-host it for free or use Kaleidos's managed cloud service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Taiga natively supports both Scrum and Kanban workflows, including sprint planning, backlog prioritization, epics, and visual Kanban boards that teams can customize to their process.$q$, $q$The platform includes issue and bug tracking, customizable dashboards for project visibility, integrations with tools like GitHub, GitLab, and Slack, and support for 20 or more interface languages, reflecting its open-source, community-driven development.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Taiga's cloud-hosted plans start with a free tier offering one public and one private project with 10MB of storage, useful for small or personal projects. Paid cloud tiers, Enthusiast, Basic, and Premium, scale up project limits, storage, and support level, priced from about 5 euros per month up to about 60 euros per month, with annual billing available at a discount.$q$, $q$Organizations that want dedicated infrastructure can purchase Taiga Private Cloud, a managed dedicated instance, or an On Premise deployment with priority support and SLA, both at custom quoted pricing. Because Taiga is fully open source, teams can also self-host it entirely for free using their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd0bc05e-d67e-4870-a277-70ee9d9c0af0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
