-- Enrichment marathon batch: Synthesia, Synup, Tableau, Tablein, Tabnine, Tabs, TagSpaces, Taiga

-- в”Ђв”Ђ Synthesia в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Synthesia is an AI video generation platform that turns text scripts into professional videos featuring AI avatars, eliminating the need for cameras, actors, or film crews.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $18/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$About 600 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Synthesia Review 2026: AI Video Generator Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Synthesia turns text scripts into AI avatar videos. See 2026 pricing plans, key features, pros and cons, and FAQs for this London-based AI video platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Synthesia is a London-based AI video generation platform founded in 2017 by Lourdes Agapito, Matthias Niessner, Victor Riparbelli, and Steffen Tjerrild. It lets users create professional videos from a text script by pairing it with an AI avatar and synthetic voiceover, removing the need for cameras, actors, studios, or film crews. The platform offers 180 or more stock AI avatars plus custom personal avatars trained on real people, supports translation and dubbing into 80 or more languages, and includes an API for programmatic video generation. Synthesia is used heavily for corporate training, internal communications, product marketing, sales enablement, and e-learning content, and reports serving 60,000 or more businesses including a large share of the Fortune 100. Pricing starts with a free plan offering 10 minutes of watermarked video per month, followed by paid Starter and Creator subscription tiers priced per minute of video with more avatars, downloads, and API access, and a custom-priced Enterprise tier with unlimited minutes, SSO, and dedicated support. The company has raised significant venture funding at a multibillion-dollar valuation and is headquartered at Regent's Place in London. It holds a 4.7-star rating from thousands of reviews on G2, with users praising speed and ease of use.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5ac53984-b400-454f-baed-b707bfdb12ec';

