-- в”Ђв”Ђ Tableau в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tableau is an enterprise business intelligence and data visualization platform, owned by Salesforce, that helps teams build interactive dashboards and explore data visually.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$15/user/month (Viewer, Standard Edition, billed annually)$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tableau Review 2026: BI and Data Visualization Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Tableau is Salesforce's enterprise BI platform. See 2026 Creator, Explorer, and Viewer pricing, key features, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tableau is an enterprise business intelligence and data visualization platform originally founded in 2003 in Mountain View, California, and now headquartered in Seattle, Washington. It was acquired by Salesforce in 2019 in an all-stock deal worth about 15.7 billion dollars and now operates as Salesforce's analytics platform. Tableau lets business users connect to a wide range of data sources and build interactive dashboards, charts, and reports through a largely drag-and-drop interface, without needing to write code. Core products include Tableau Desktop and Tableau Cloud for authoring and publishing, Tableau Prep for data preparation, and Tableau Pulse, an AI-driven layer that surfaces automated insights and natural language answers. Pricing is role-based and billed annually per user, split into Viewer, Explorer, and Creator licenses, each available in Standard or Enterprise editions, with Standard Edition Creator around 75 dollars per user per month and Enterprise Edition Creator around 115 dollars per user per month. Every deployment requires at least one Creator license. Tableau is widely used by data analysts, business intelligence teams, and executives at large and mid-size organizations for self-service analytics and governed enterprise reporting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3420577a-4640-4828-a64b-5afe612e65be';

