-- в”Ђв”Ђ Tablein в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tablein is a restaurant table reservation and booking system that helps restaurants manage bookings, guest data, and no-shows through a booking widget, dashboard, and free reservation website.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$About $79/month (Starter plan, EUR 67/month)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Kaunas, Lithuania$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tablein Review 2026: Restaurant Reservation Software Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Tablein is a restaurant table booking system. See 2026 Starter, Growth, and Success pricing, key features, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tablein is a restaurant table reservation and booking system founded in 2018 and based in Kaunas, Lithuania, led by founder and CEO Paulius. It gives restaurants a booking widget for their website, a management dashboard, and a free standalone reservation website so guests can book a table online instead of by phone. The platform includes a guest database and lightweight CRM, automated email and SMS reservation reminders aimed at reducing no-shows, table and floor plan management, deposit and payment processing, and performance reporting. Tablein is priced per restaurant location on three monthly plans, Starter, Growth, and Success, differentiated mainly by the number of included reservations per month, with each extra reservation billed individually once the included allowance is used, and an annual billing option that offers roughly two months free. There is a 14-day free trial and no setup fees or long-term contract requirement. Tablein has grown as a bootstrapped, independently funded company without disclosed venture capital, reporting a modest annual recurring revenue. It is primarily aimed at independent restaurants and small multi-location restaurant groups looking for an affordable alternative to larger reservation platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c81486a4-91b4-43a3-938b-cb4a8e444d88';

